import React, { useEffect, useState } from 'react';
import { Users, Utensils, Music, CheckCircle } from 'lucide-react';

export default function AdminDashboard() {
  const [guests, setGuests] = useState([]);
  const [stats, setStats] = useState({ total: 0, veg: 0, nonVeg: 0 });

  useEffect(() => {
    fetch('http://localhost:5000/api/rsvp')
      .then(res => res.json())
      .then(data => {
        setGuests(data);
        const total = data.reduce((acc, g) => acc + (g.guests || 1), 0);
        // Assuming your RSVPForm sends 'Veg' or 'Non-Veg'
        const vegCount = data.filter(g => g.foodPreference === 'Veg').length;
        setStats({ total, veg: vegCount, nonVeg: data.length - vegCount });
      });
  }, []);

  return (
    <div className="min-h-screen bg-[#FAF9F6] p-8 pt-24">
      <div className="max-w-6xl mx-auto">
        <h2 className="font-serif text-4xl mb-8 text-luxury-dark">Guest Management</h2>
        
        {/* Quick Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          <StatCard icon={<Users />} label="Total Guests" value={stats.total} color="bg-blue-50" />
          <StatCard icon={<Utensils />} label="Veg / Non-Veg" value={`${stats.veg} / ${stats.nonVeg}`} color="bg-green-50" />
          <StatCard icon={<Music />} label="Song Requests" value={guests.filter(g => g.songRequest).length} color="bg-purple-50" />
        </div>

        {/* Guest Table */}
        <div className="bg-white rounded-3xl shadow-sm overflow-hidden border border-gray-100">
          <table className="w-full text-left">
            <thead className="bg-gray-50 text-[10px] uppercase tracking-widest text-gray-400">
              <tr>
                <th className="p-4">Name</th>
                <th className="p-4">Status</th>
                <th className="p-4">Guests</th>
                <th className="p-4">Food</th>
                <th className="p-4">Song Request</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {guests.map((guest, i) => (
                <tr key={i} className="border-t border-gray-50 hover:bg-gray-50/50 transition-colors">
                  <td className="p-4 font-medium">{guest.name}</td>
                  <td className="p-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] ${guest.attendance === 'yes' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                      {guest.attendance.toUpperCase()}
                    </span>
                  </td>
                  <td className="p-4">{guest.guests}</td>
                  <td className="p-4 text-gray-500">{guest.foodPreference}</td>
                  <td className="p-4 italic text-luxury-gold">{guest.songRequest || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function StatCard({ icon, label, value, color }) {
  return (
    <div className={`${color} p-6 rounded-3xl flex items-center gap-4`}>
      <div className="text-luxury-dark">{icon}</div>
      <div>
        <p className="text-[10px] uppercase tracking-widest text-gray-500">{label}</p>
        <p className="text-2xl font-serif text-luxury-dark">{value}</p>
      </div>
    </div>
  );
}
